  1	import * as React from 'react';
  2	import { FDF_FLAG } from '@odf/core/redux';
  3	import { RemoteClusterKind } from '@odf/core/types/scale';
  4	import { isClusterIgnored, isExternalCluster } from '@odf/core/utils/odf';
  5	import { DASH } from '@odf/shared/constants';
  6	import { useWatchStorageClusters } from '@odf/shared/hooks/useWatchStorageClusters';
  7	import { resourceStatus } from '@odf/shared/status/Resource';
  8	import { Status } from '@odf/shared/status/Status';
  9	import { StorageClusterPhase } from '@odf/shared/types/storage';
 10	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 11	import {
 12	  K8sResourceKind,
 13	  StatusIconAndText,
 14	  useFlag,
 15	  YellowExclamationTriangleIcon,
 16	} from '@openshift-console/dynamic-plugin-sdk';
 17	import classNames from 'classnames';
 18	import * as _ from 'lodash-es';
 19	import { TFunction } from 'react-i18next';
 20	import { useNavigate } from 'react-router-dom-v5-compat';
 21	import {
 22	  Button,
 23	  ButtonVariant,
 24	  Card,
 25	  CardBody,
 26	  CardHeader,
 27	  CardProps,
 28	  CardTitle,
 29	  DescriptionList,
 30	  DescriptionListDescription,
 31	  DescriptionListGroup,
 32	  DescriptionListTerm,
 33	  Stack,
 34	  StackItem,
 35	} from '@patternfly/react-core';
 36	import { ArrowRightIcon } from '@patternfly/react-icons';
 37	import './ExternalSystemsCard.scss';
 38	
 39	const getClustersStatuses = (
 40	  clusters: K8sResourceKind[] = [],
 41	  t: TFunction
 42	): React.ReactNode => {
 43	  let [healthy, error, warning] = [0, 0, 0];
 44	  for (const cluster of clusters) {
 45	    const clusterStatus = resourceStatus(cluster);
 46	    if (clusterStatus === StorageClusterPhase.Ready) {
 47	      healthy++;
 48	    } else if (clusterStatus === StorageClusterPhase.Error) {
 49	      error++;
 50	    } else {
 51	      // We group all other statuses as warning.
 52	      warning++;
 53	    }
 54	  }
 55	
 56	  return (
 57	    <>
 58	      {error > 0 && (
 59	        <Status
 60	          status={StorageClusterPhase.Error}
 61	          title={String(error)}
 62	          className="pf-v6-u-mr-lg"
 63	        />
 64	      )}
 65	      {warning > 0 && (
 66	        <StatusIconAndText
 67	          icon={<YellowExclamationTriangleIcon />}
 68	          title={String(warning)}
 69	          className="pf-v6-u-mr-lg"
 70	        />
 71	      )}
 72	      {healthy > 0 && (
 73	        <Status status={StorageClusterPhase.Ready} title={String(healthy)} />
 74	      )}
 75	      {healthy + error + warning === 0 && (
 76	        <span className="pf-v5-u-disabled-color-100">
 77	          {t('No external systems connected')}
 78	        </span>
 79	      )}
 80	    </>
 81	  );
 82	};
 83	
 84	const getScaleClustersStatuses = (
 85	  clusters: RemoteClusterKind[] = [],
 86	  t: TFunction
 87	): React.ReactNode => {
 88	  let [healthy, error, warning] = [0, 0, 0];
 89	  for (const cluster of clusters) {
 90	    const clusterStatus = cluster.status?.conditions?.find(
 91	      (condition) => condition.type === 'Available'
 92	    )?.status;
 93	    if (clusterStatus === 'True') {
 94	      healthy++;
 95	    }
 96	    if (clusterStatus === 'False') {
 97	      error++;
 98	    }
 99	    if (clusterStatus === 'Unknown') {
100	      warning++;
101	    }
102	  }
103	  return (
104	    <>
105	      {error > 0 && (
106	        <Status
107	          status={StorageClusterPhase.Error}
108	          title={String(error)}
109	          className="pf-v6-u-mr-lg"
110	        />
111	      )}
112	      {warning > 0 && (
113	        <StatusIconAndText
114	          icon={<YellowExclamationTriangleIcon />}
115	          title={String(warning)}
116	          className="pf-v6-u-mr-lg"
117	        />
118	      )}
119	      {healthy > 0 && (
120	        <Status status={StorageClusterPhase.Ready} title={String(healthy)} />
121	      )}
122	      {healthy + error + warning === 0 && (
123	        <span className="pf-v5-u-disabled-color-100">
124	          {t('No external systems connected')}
125	        </span>
126	      )}
127	    </>
128	  );
129	};
130	export const ExternalSystemsCard: React.FC<CardProps> = ({ className }) => {
131	  const { t } = useCustomTranslation();
132	  const { storageClusters, flashSystemClusters, remoteClusters } =
133	    useWatchStorageClusters();
134	  const navigate = useNavigate();
135	
136	  const isFDF = useFlag(FDF_FLAG);
137	
138	  const cephClustersStatuses =
139	    storageClusters?.loaded && !storageClusters?.loadError
140	      ? getClustersStatuses(
141	          storageClusters?.data?.filter(
142	            (cluster) =>
143	              !isClusterIgnored(cluster) && isExternalCluster(cluster)
144	          ),
145	          t
146	        )
147	      : DASH;
148	  const fsClustersStatuses =
149	    flashSystemClusters?.loaded && !flashSystemClusters?.loadError
150	      ? getClustersStatuses(flashSystemClusters?.data, t)
151	      : DASH;
152	  const scaleClustersStatuses =
153	    (isFDF ? remoteClusters?.loaded : true) && !remoteClusters?.loadError
154	      ? getScaleClustersStatuses(remoteClusters?.data, t)
155	      : DASH;
156	
157	  return (
158	    <Card
159	      className={classNames(className, 'odf-external-system-card')}
160	      isFlat={true}
161	    >
162	      <CardHeader>
163	        <CardTitle>{t('External systems')}</CardTitle>
164	      </CardHeader>
165	      <CardBody>
166	        <Stack>
167	          <StackItem>
168	            <DescriptionList>
169	              {isFDF && (
170	                <DescriptionListGroup>
171	                  <DescriptionListTerm>
172	                    {t('IBM Scale System')}
173	                  </DescriptionListTerm>
174	                  <DescriptionListDescription>
175	                    {scaleClustersStatuses}
176	                  </DescriptionListDescription>
177	                </DescriptionListGroup>
178	              )}
179	              <DescriptionListGroup>
180	                <DescriptionListTerm>
181	                  {t('IBM Flash System')}
182	                </DescriptionListTerm>
183	                <DescriptionListDescription>
184	                  {fsClustersStatuses}
185	                </DescriptionListDescription>
186	              </DescriptionListGroup>
187	              <DescriptionListGroup>
188	                <DescriptionListTerm>{t('Red Hat Ceph')}</DescriptionListTerm>
189	                <DescriptionListDescription>
190	                  {cephClustersStatuses}
191	                </DescriptionListDescription>
192	              </DescriptionListGroup>
193	            </DescriptionList>
194	          </StackItem>
195	          <StackItem isFilled></StackItem>
196	          <StackItem>
197	            <Button
198	              variant={ButtonVariant.link}
199	              icon={<ArrowRightIcon />}
200	              iconPosition="end"
201	              className="pf-v6-u-font-size-lg odf-cluster-card__storage-link"
202	              onClick={() => navigate('/odf/external-systems')}
203	            >
204	              {t('View external systems')}
205	            </Button>
206	          </StackItem>
207	        </Stack>
208	      </CardBody>
209	    </Card>
210	  );
211	};

